import{_ as i,o as t,c as a,a3 as n}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"数据筛选工具","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/data-filter.md","filePath":"user-guide/tools/data-filter.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/data-filter.md"};function e(h,s,o,r,d,p){return t(),a("div",null,[...s[0]||(s[0]=[n(`<h1 id="数据筛选工具" tabindex="-1">数据筛选工具 <a class="header-anchor" href="#数据筛选工具" aria-label="Permalink to &quot;数据筛选工具&quot;">​</a></h1><blockquote><p>快速从 JSON / YAML 数组数据中精准提取你需要的条目。</p></blockquote><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>数据筛选工具提供了一套直观的图形界面，让你无需编写代码就能对结构化列表数据进行多条件过滤。无论你在处理配置文件、接口返回的列表数据，还是批量分析日志中的记录项，都可以通过设置简单的筛选条件快速定位目标数据。</p><p><strong>核心功能：</strong></p><ul><li><strong>多格式输入</strong>：天然支持 JSON 和 YAML 两种数据格式，自动识别无需手动切换。</li><li><strong>丰富的操作符</strong>：提供等于、不等于、包含、数值比较、真值/假值判断以及自定义脚本共 10 种筛选操作符。</li><li><strong>多条件组合</strong>：支持添加多个筛选条件，条件间为 <strong>AND</strong> 逻辑，单个条件内的多键为 <strong>OR</strong> 逻辑。</li><li><strong>深层路径访问</strong>：通过 <code>dataPath</code> 参数支持访问嵌套对象中的数组（如 <code>data.items</code>）。</li><li><strong>预设系统</strong>：可将常用的筛选规则组合保存为预设，随时快速复用。</li><li><strong>结果一键复用</strong>：筛选结果支持一键复制到剪贴板，或直接发送到 LLM 聊天面板继续分析。</li></ul><hr><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="基本流程" tabindex="-1">基本流程 <a class="header-anchor" href="#基本流程" aria-label="Permalink to &quot;基本流程&quot;">​</a></h3><ol><li>在左侧编辑区粘贴或输入你的 JSON / YAML 数组数据。</li><li>在中间的配置区设置筛选条件（至少一个）。</li><li>点击底部 <strong>「执行筛选」</strong> 按钮。</li><li>在右侧结果区查看筛选结果，统计信息会显示「筛选后条数 / 总条数」。</li></ol><h3 id="示例-筛选已启用的配置项" tabindex="-1">示例：筛选已启用的配置项 <a class="header-anchor" href="#示例-筛选已启用的配置项" aria-label="Permalink to &quot;示例：筛选已启用的配置项&quot;">​</a></h3><p>假设你有以下 JSON 数据：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;插件 A&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2.0&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;插件 B&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">false</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1.5&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;插件 C&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;enabled&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;version&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;3.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>操作步骤：</p><ol><li>将上述 JSON 粘贴到左侧编辑区。</li><li>中间配置区默认已有一条条件 <code>enabled 等于 true</code>，无需修改。</li><li>点击 <strong>「执行筛选」</strong>。</li><li>右侧结果区将只显示两条启用的配置项（插件 A 和插件 C），统计显示 <code>2 / 3 项</code>。</li></ol><hr><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="原始数据输入" tabindex="-1">原始数据输入 <a class="header-anchor" href="#原始数据输入" aria-label="Permalink to &quot;原始数据输入&quot;">​</a></h3><p>支持两种数据格式的输入：</p><ul><li><strong>JSON</strong>：标准的 JSON 数组或包含数组的 JSON 对象。</li><li><strong>YAML</strong>：YAML 格式的数组数据。</li><li>工具会自动根据内容判断格式，并在输入区右上角显示当前识别到的格式标签。</li></ul><p>支持通过工具栏的 <strong>「粘贴」</strong> 按钮从系统剪贴板快速导入数据。</p><h3 id="筛选规则配置" tabindex="-1">筛选规则配置 <a class="header-anchor" href="#筛选规则配置" aria-label="Permalink to &quot;筛选规则配置&quot;">​</a></h3><h4 id="数据路径-datapath" tabindex="-1">数据路径 (dataPath) <a class="header-anchor" href="#数据路径-datapath" aria-label="Permalink to &quot;数据路径 (dataPath)&quot;">​</a></h4><p>当你的数据是一个包裹在对象中的数组时（而非纯数组），需要通过「数据路径」告诉工具数组在哪里。</p><p><strong>示例：</strong></p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;data&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;items&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;项目A&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">      { </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;id&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">&quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;项目B&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>此时你需要在「数据路径」输入框中填写 <code>data.items</code>，工具会自动定位到目标数组。</p><blockquote><p><strong>提示</strong>：如果输入数据本身就是数组（以 <code>[</code> 开头），数据路径留空即可。</p></blockquote><h4 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h4><p>每个筛选条件包含以下字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th><th>详情</th></tr></thead><tbody><tr><td><strong>启用开关</strong></td><td>控制该条件是否生效</td><td>可临时关闭某个条件，无需删除</td></tr><tr><td><strong>键名</strong></td><td>要匹配的属性路径</td><td>支持 <code>a.b.c</code> 深层访问，<strong>也支持英文逗号分隔多个键名实现 OR 匹配</strong></td></tr><tr><td><strong>操作符</strong></td><td>匹配规则</td><td>共 10 种操作符可选（见下表）</td></tr><tr><td><strong>目标值</strong></td><td>用于匹配的值</td><td>等于/不等于等操作符需要填写，真值/假值/自定义脚本不需要</td></tr></tbody></table><h4 id="操作符说明" tabindex="-1">操作符说明 <a class="header-anchor" href="#操作符说明" aria-label="Permalink to &quot;操作符说明&quot;">​</a></h4><table tabindex="0"><thead><tr><th>操作符</th><th>说明</th><th>示例场景</th></tr></thead><tbody><tr><td>等于</td><td>严格相等匹配</td><td>筛选状态为 <code>&quot;active&quot;</code> 的项</td></tr><tr><td>不等于</td><td>严格不等匹配</td><td>排除状态为 <code>&quot;deleted&quot;</code> 的项</td></tr><tr><td>包含</td><td>字符串包含匹配</td><td>筛选名称中包含 <code>&quot;test&quot;</code> 的项</td></tr><tr><td>大于</td><td>数值大于</td><td>筛选价格大于 100 的项</td></tr><tr><td>大于等于</td><td>数值大于等于</td><td>筛选评分 &gt;= 4.5 的项</td></tr><tr><td>小于</td><td>数值小于</td><td>筛选库存量小于 10 的项</td></tr><tr><td>小于等于</td><td>数值小于等于</td><td>筛选年龄 &lt;= 30 的项</td></tr><tr><td>真值</td><td>值为真（存在且非假值）</td><td>筛选已启用的开关</td></tr><tr><td>假值</td><td>值为假（不存在或为假值）</td><td>筛选未分配的标签</td></tr><tr><td>自定义脚本</td><td>执行 JS 表达式</td><td>处理复杂逻辑（见高级用法）</td></tr></tbody></table><blockquote><p><strong>提示</strong>：填入目标值时会自动转换，<code>&quot;true&quot;</code> 和 <code>&quot;false&quot;</code> 会被识别为布尔值，纯数字字符串会自动转为数值。</p></blockquote><h4 id="条件组合逻辑" tabindex="-1">条件组合逻辑 <a class="header-anchor" href="#条件组合逻辑" aria-label="Permalink to &quot;条件组合逻辑&quot;">​</a></h4><ul><li><strong>条件之间</strong>：多个条件为 <strong>AND</strong> 关系，数据项必须满足 <strong>所有</strong> 启用条件才算匹配。</li><li><strong>单个条件内</strong>：键名支持逗号分隔，多个键名之间为 <strong>OR</strong> 关系，只要其中一个键的值满足条件即算通过。</li></ul><blockquote><p>简单来说：<strong>条件之间取交集（AND），键名之间取并集（OR）</strong>。</p></blockquote><h4 id="预设管理" tabindex="-1">预设管理 <a class="header-anchor" href="#预设管理" aria-label="Permalink to &quot;预设管理&quot;">​</a></h4><p>如果你经常使用相同的筛选规则，可以将其保存为预设：</p><ol><li>配置好筛选条件后，点击配置区顶部的 <strong>「+」</strong> 按钮。</li><li>输入预设名称并保存。</li><li>下次使用时从预设下拉列表中选择即可一键加载。</li></ol><p>预设还支持 <strong>更新</strong>（覆盖保存当前条件）、<strong>重命名</strong> 和 <strong>删除</strong> 管理。</p><h3 id="筛选结果" tabindex="-1">筛选结果 <a class="header-anchor" href="#筛选结果" aria-label="Permalink to &quot;筛选结果&quot;">​</a></h3><p>执行筛选后，右侧结果区会展示：</p><ul><li><strong>统计信息</strong>：显示 <code>筛选后条数 / 总条数</code> 的统计。</li><li><strong>筛选结果</strong>：只读的代码编辑器展示筛选后的数据，格式与输入保持一致。</li><li><strong>结果操作</strong>：支持 <strong>复制结果</strong> 到剪贴板，或 <strong>发送到聊天</strong> 面板进行后续 LLM 分析。</li></ul><blockquote><p>如果没有匹配到任何项，会提示「筛选完成，没有匹配的项」。</p></blockquote><hr><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="自定义脚本过滤" tabindex="-1">自定义脚本过滤 <a class="header-anchor" href="#自定义脚本过滤" aria-label="Permalink to &quot;自定义脚本过滤&quot;">​</a></h3><p>当内置操作符无法满足需求时，可以使用「自定义脚本」操作符。你需要编写一个 JavaScript 表达式，该表达式应返回 <code>true</code>（保留）或 <code>false</code>（剔除）。</p><p><strong>脚本上下文：</strong></p><ul><li><code>item</code>：当前遍历的数组元素。</li><li><code>value</code>：你在目标值输入框中填写的值。</li></ul><p><strong>示例 1：筛选价格在特定范围的商品</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">item.price </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 50</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item.price </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 200</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><strong>示例 2：筛选名称长度超过 10 个字符的项</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">item.name.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">length</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p><strong>示例 3：组合多字段复杂逻辑</strong></p><div class="language-javascript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">javascript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">item.enabled </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&amp;&amp;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (item.type </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">===</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;premium&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> item.priority </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre></div><blockquote><p><strong>注意</strong>：自定义脚本会在页面上通过 <code>new Function</code> 动态执行，请不要在此处执行任何有副作用的操作。</p></blockquote><h3 id="自动状态恢复" tabindex="-1">自动状态恢复 <a class="header-anchor" href="#自动状态恢复" aria-label="Permalink to &quot;自动状态恢复&quot;">​</a></h3><p>工具会自动保存你的输入数据和筛选配置（防抖 800ms）。关闭工具后重新打开，上次编辑的内容会自动恢复，方便你继续工作。</p><hr><h2 id="常见问题-faq" tabindex="-1">常见问题 (FAQ) <a class="header-anchor" href="#常见问题-faq" aria-label="Permalink to &quot;常见问题 (FAQ)&quot;">​</a></h2><h3 id="q1-为什么执行筛选后提示「输入数据不是数组」" tabindex="-1">Q1：为什么执行筛选后提示「输入数据不是数组」？ <a class="header-anchor" href="#q1-为什么执行筛选后提示「输入数据不是数组」" aria-label="Permalink to &quot;Q1：为什么执行筛选后提示「输入数据不是数组」？&quot;">​</a></h3><p>这通常有两种情况：</p><ul><li>你输入的数据本身就是一个对象（如 <code>{}</code>），而非数组。如果数组在对象的某个字段中，请在「数据路径」中输入对应路径。</li><li>dataPath 配置不正确，导致定位到的数据不是数组。检查你填写的路径是否正确。</li></ul><h3 id="q2-如何匹配字段值包含多个关键词" tabindex="-1">Q2：如何匹配字段值包含多个关键词？ <a class="header-anchor" href="#q2-如何匹配字段值包含多个关键词" aria-label="Permalink to &quot;Q2：如何匹配字段值包含多个关键词？&quot;">​</a></h3><p>单个「包含」操作符只能匹配一个关键词。如果你需要同时匹配多个关键词（如名称同时包含 &quot;A&quot; 和 &quot;B&quot;），可以添加多个「包含」条件（条件间为 AND 逻辑），或者使用「自定义脚本」操作符编写更复杂的表达式。</p><h3 id="q3-条件保存为预设后会不会丢失" tabindex="-1">Q3：条件保存为预设后会不会丢失？ <a class="header-anchor" href="#q3-条件保存为预设后会不会丢失" aria-label="Permalink to &quot;Q3：条件保存为预设后会不会丢失？&quot;">​</a></h3><p>预设会持久化保存在应用的配置目录中（<code>AppData/data-filter/config.json</code>），不会因重启应用而丢失。你也可以通过「更新预设」功能覆盖保存当前条件。</p><h3 id="q4-筛选结果中的数据格式为什么会变化" tabindex="-1">Q4：筛选结果中的数据格式为什么会变化？ <a class="header-anchor" href="#q4-筛选结果中的数据格式为什么会变化" aria-label="Permalink to &quot;Q4：筛选结果中的数据格式为什么会变化？&quot;">​</a></h3><p>工具会保持与输入格式一致：输入是 JSON 则输出 JSON，输入是 YAML 则输出 YAML。如果你发现格式不符合预期，可以检查输入数据开头的格式特征（JSON 以 <code>{</code> 或 <code>[</code> 开头，YAML 通常以键值或列表符 <code>-</code> 开头）。</p><h3 id="q5-为什么「发送到聊天」按钮置灰不可用" tabindex="-1">Q5：为什么「发送到聊天」按钮置灰不可用？ <a class="header-anchor" href="#q5-为什么「发送到聊天」按钮置灰不可用" aria-label="Permalink to &quot;Q5：为什么「发送到聊天」按钮置灰不可用？&quot;">​</a></h3><p>「发送到聊天」功能需要连接并配置了 LLM 服务才能使用。请先确保在应用设置中正确配置了 LLM API 地址和相关参数。</p><hr><div class="info custom-block"><p class="custom-block-title">INFO</p><p><strong>💡 使用提示</strong>：对于包含大量数据的文件（超过数千条），建议先通过 dataPath 定位到精确的目标数组，避免因嵌套层级过深导致的性能问题。</p></div>`,75)])])}const E=i(l,[["render",e]]);export{g as __pageData,E as default};
